/**
 * QTI Composer - UI Component
 *
 * Displays the composed QTI XML from item context.
 * Customize styling as needed.
 */

import { consume } from '@lit/context';
import { html, LitElement } from 'lit';
import { customElement, state } from 'lit/decorators.js';
import { buildAssessmentItemXml, formatXml, type ComposerItemContext } from '@qti-editor/core/composer';
import { itemContext, type ItemContext } from '@qti-editor/core/item-context';

@customElement('qti-composer')
export class QtiComposer extends LitElement {
  @consume({ context: itemContext, subscribe: true })
  @state()
  public itemContext?: ItemContext;

  #xmlUrl = '';
  #formattedXml = '';

  override createRenderRoot() {
    return this;
  }

  override willUpdate(changedProperties: Map<string, unknown>) {
    super.willUpdate(changedProperties);
    if (changedProperties.has('itemContext')) {
      const xml = buildAssessmentItemXml(this.itemContext as ComposerItemContext);
      this.#setXmlUrl(xml);
      this.#formattedXml = formatXml(xml);
    }
  }

  override disconnectedCallback() {
    super.disconnectedCallback();
    this.#revokeXmlUrl();
  }

  #setXmlUrl(xml: string) {
    this.#revokeXmlUrl();
    if (!xml.trim()) {
      this.#xmlUrl = '';
      return;
    }
    const xmlWithDeclaration = xml.startsWith('<?xml')
      ? xml
      : `<?xml version="1.0" encoding="UTF-8"?>\n${xml}`;
    const xmlFile = new File([xmlWithDeclaration], 'assessment-item.xml', {
      type: 'application/xml',
    });
    this.#xmlUrl = URL.createObjectURL(xmlFile);
  }

  #revokeXmlUrl() {
    if (!this.#xmlUrl) return;
    URL.revokeObjectURL(this.#xmlUrl);
    this.#xmlUrl = '';
  }

  override render() {
    return html`
      <h3 class="text-sm font-semibold mb-2">Composer XML</h3>
      <section class="card border border-base-300/50 bg-base-100 p-4">
        ${this.#xmlUrl
          ? html`
              <a
                class="mb-2 inline-block text-xs link link-primary"
                href=${this.#xmlUrl}
                target="_blank"
                rel="noopener noreferrer"
              >
                Open XML in new tab
              </a>
              <pre class="m-0 max-h-80 overflow-auto rounded border border-base-300/50 bg-base-200 p-3 text-xs">${this.#formattedXml}</pre>
            `
          : html`<p class="text-xs text-base-content/70">No XML available.</p>`}
      </section>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'qti-composer': QtiComposer;
  }
}

/**
 * QTI Composer Example - Entry Point
 *
 * Re-exports all parts needed for the QTI composer example.
 */

// Core types and functions
export type { ComposerItemContext } from '@qti-editor/core/composer';
export { buildAssessmentItemXml, formatXml, extractResponseDeclarations } from '@qti-editor/core/composer';

// Item context
export type { ItemContext } from '@qti-editor/core/item-context';
export { itemContext, itemContextVariables } from '@qti-editor/core/item-context';

// Editor example (provides context)
export { QtiComposerProvider } from './editor.js';

// UI component
export { QtiComposer } from '../../ui/qti-composer/index.js';

/**
 * QTI Composer Editor Example
 *
 * This file demonstrates how to provide item context and use
 * the QtiComposer component in a Lit application.
 */

import '../../ui/qti-composer/index.js';

import { provide } from '@lit/context';
import { html, LitElement } from 'lit';
import { customElement, state } from 'lit/decorators.js';
import { itemContext, type ItemContext } from '@qti-editor/core/item-context';

/**
 * Example provider component that wraps the QtiComposer.
 * In a real application, you would provide the itemContext from
 * your editor state or data layer.
 */
@customElement('qti-composer-provider')
export class QtiComposerProvider extends LitElement {
  /**
   * The item context to provide to child components.
   * Update this when your item data changes.
   */
  @provide({ context: itemContext })
  @state()
  public itemCtx: ItemContext = {
    identifier: 'example-item',
    title: 'Example Assessment Item',
    variables: [],
    itemBody: undefined,
  };

  override createRenderRoot() {
    return this;
  }

  /**
   * Updates the item context. Call this when your item data changes.
   */
  public updateItemContext(ctx: Partial<ItemContext>) {
    this.itemCtx = { ...this.itemCtx, ...ctx };
  }

  override render() {
    return html`
      <div class="qti-composer-wrapper">
        <qti-composer></qti-composer>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'qti-composer-provider': QtiComposerProvider;
  }
}
